package com.tjclp.xl.drawings

import scala.collection.immutable.ArraySeq

/**
 * Tiny valid image byte templates for drawing-layer tests and generators (GH-221).
 *
 * The four raster templates are 2x3 px, produced once via JDK ImageIO and embedded as hex (the
 * fixture-script precedent: deterministic bytes, no test-time image library). `fixturePng3x3` is
 * the exact payload of xl-ooxml's image.xlsx fixture (3x3 px = 28575 EMU at 96 DPI).
 */
object TestImages:

  private def hex(s: String): ArraySeq[Byte] =
    ArraySeq.unsafeWrapArray(s.grouped(2).map(Integer.parseInt(_, 16).toByte).toArray)

  /** 2x3 RGB PNG (ImageIO). */
  val png2x3: ArraySeq[Byte] = hex(
    "89504e470d0a1a0a0000000d4948445200000002000000030802000000368849d60000000e49444154785e63f8cf8001fe0300150001ff0bfeb2140000000049454e44ae426082"
  )

  /** 2x3 GIF (ImageIO). */
  val gif2x3: ArraySeq[Byte] = hex(
    "47494638396102000300f100000000000000ffff00000000002c00000000020003004108080005000010606040003b"
  )

  /** 2x3 baseline JPEG (ImageIO). */
  val jpeg2x3: ArraySeq[Byte] = hex(
    ""
  )

  /** 2x3 24-bit BMP (ImageIO). */
  val bmp2x3: ArraySeq[Byte] = hex(
    "424d4e000000000000003600000028000000020000000300000001001800000000001800000000000000000000000000000000000000000000ff0000000000000000000000000000ff0000000000"
  )

  /** The exact 3x3 PNG embedded in xl-ooxml's image.xlsx fixture. */
  val fixturePng3x3: ArraySeq[Byte] = hex(
    "89504e470d0a1a0a0000000d4948445200000003000000030802000000d94a22e8000000104944415478da637851ac03410c585800d4eb0dc0ea7a6d6c0000000049454e44ae426082"
  )

  /** Minimal placeable-WMF header bytes: detectable format, unsniffable dimensions. */
  val wmfHeader: ArraySeq[Byte] = hex("d7cdc69a000000000000000000000000")
